function getTypeTimerNow() {
    // UTC+7 offset
    var OFFSET = 7 * 3600000;
    // timestamp hiện tại
    var now = Date.now() + OFFSET;
    var d = new Date(now);
    // minute of day
    var minutes = d.getUTCHours() * 60 + d.getUTCMinutes();
    // getUTCDay(): 0=Sun
    var day = d.getUTCDay();
    var dayName;
    switch (day) {
        case 1: dayName = "Mon"; break;
        case 2: dayName = "Tue"; break;
        case 3: dayName = "Wed"; break;
        case 4: dayName = "Thu"; break;
        case 5: dayName = "Fri"; break;
        case 6: dayName = "Sat"; break;
        default: dayName = "Sun";
    }

    return {
        type: dayName + "_" + minutes,
        typeAll:"All_"+minutes
    }
}
var metadata = getTypeTimerNow();
var msgType = "POST_TELEMETRY_REQUEST";
return {
    msg: {},
    metadata: metadata,
    msgType: msgType
};

