// ===============================
// Utils
// ===============================

// convert HH:mm:ss -> ms trong ngày
function timeToMs(t) {
    var p = t.split(":");
    return (
        parseInt(p[0], 10) * 3600000 +
        parseInt(p[1], 10) * 60000 +
        parseInt(p[2], 10) * 1000
    );
}

// ===============================
// 1. Check 1 key
// ===============================
function checkKeyCondition(cond, deviceState) {
    if (!deviceState) return false;
    var v = deviceState[cond.key];
    if (typeof v !== "number") return false;
    if (cond.operator === "=") {
        return v === cond.value;
    }
    if (cond.operator === "RANGE") {
        if (typeof cond.min !== "number" || typeof cond.max !== "number") {
            return false;
        }
        if (cond.mode === "INSIDE") {
            return v >= cond.min && v <= cond.max;
        }
        if (cond.mode === "OUTSIDE") {
            return v < cond.min || v > cond.max;
        }
    }
    return false;
}


// ===============================
// 2. Check device
// ===============================
function checkDevice(deviceRule, stateMap) {

    var deviceState = stateMap[deviceRule.entityName];

    if (!deviceState) return false;

    var triggers = deviceRule.dataTrigger;

    if (!triggers || !triggers.length) return false;

    for (var i = 0; i < triggers.length; i++) {

        if (!checkKeyCondition(triggers[i], deviceState)) {
            return false;
        }
    }

    return true;
}


// ===============================
// 3. Check validityPeriod
// ===============================
