var DAY_BITS = [64,1,2,4,8,16,32];// 0=Sun 1=Mon 2=Tue 3=Wed 4=Thu 5=Fri 6=Sat
var now = new Date();
function isTodayInRepeat(repeat, now) {
    // đảm bảo repeat là integer hợp lệ
    if ((repeat | 0) !== repeat || repeat < 0 || repeat > 127) {
        return false;
    }
    now = now || new Date();
    var todayBit = DAY_BITS[now.getDay()];
    return (repeat & todayBit) !== 0;
}

