function getDiffByEntityName(data) {
    // validate input
    if (!data || !data.dataResponse || !data.listInputDevice) {
        return [];
    }

    var result = [];
    var existedMap = {};

    // tạo map entityName đã có trong listInputDevice
    for (var i = 0; i < data.listInputDevice.length; i++) {
        var item = data.listInputDevice[i];
        if (item && item.entityName) {
            existedMap[item.entityName] = true;
        }
    }

    // duyệt dataResponse, lấy những entityName chưa tồn tại
    for (var j = 0; j < data.dataResponse.length; j++) {
        var resp = data.dataResponse[j];
        if (resp && resp.entityName && !existedMap[resp.entityName]) {
            result.push(resp);
        }
    }

    return result;
}
